import React from 'react';
import './Experience.css';

const Experience = () => {
  const experiences = [
    {
      id: 1,
      title: "AI/ML Engineer",
      company: "Tech Company",
      period: "2023 - Present",
      description: "Developing machine learning models and AI solutions for enterprise applications.",
      technologies: ["Python", "TensorFlow", "PyTorch", "AWS", "Docker"]
    },
    {
      id: 2,
      title: "Full-Stack Developer",
      company: "Startup",
      period: "2022 - 2023",
      description: "Built scalable web applications using modern technologies and best practices.",
      technologies: ["React", "Node.js", "MongoDB", "Express", "TypeScript"]
    },
    {
      id: 3,
      title: "Frontend Developer",
      company: "Digital Agency",
      period: "2021 - 2022",
      description: "Created responsive and interactive user interfaces for various client projects.",
      technologies: ["React", "JavaScript", "CSS3", "HTML5", "Git"]
    }
  ];

  return (
    <section id="experience" className="section experience">
      <div className="container">
        <h2 className="section-title">Experience</h2>
        <p className="section-subtitle">
          My professional journey and the valuable experiences that have shaped my expertise.
        </p>
        
        <div className="experience-timeline">
          {experiences.map((exp, index) => (
            <div key={exp.id} className={`timeline-item ${index % 2 === 0 ? 'left' : 'right'}`}>
              <div className="timeline-content card">
                <div className="timeline-header">
                  <h3 className="timeline-title">{exp.title}</h3>
                  <div className="timeline-company">{exp.company}</div>
                  <div className="timeline-period">{exp.period}</div>
                </div>
                
                <p className="timeline-description">{exp.description}</p>
                
                <div className="timeline-technologies">
                  {exp.technologies.map((tech, techIndex) => (
                    <span key={techIndex} className="tech-tag">{tech}</span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
